use std::fmt::{self, Display};

#[derive(Debug)]
enum PointVariant {
    IntPoint { x: i32, y: i32 },
    FloatBox { min_x: f64, max_x: f64, min_y: f64, max_y: f64 },
}

impl Display for PointVariant {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            PointVariant::IntPoint { x, y } => write!(f, "Integer Point: ({}, {})", x, y),
            PointVariant::FloatBox { min_x, max_x, min_y, max_y } => write!(f, "Float Box: [{:.1}, {:.1}] x [{:.1}, {:.1}]", min_x, max_x, min_y, max_y),
        }
    }
}

fn process_coordinate(coord: PointVariant) -> String {
    match coord {
        PointVariant::IntPoint { .. } => format!("Successfully processed an integer coordinate structure."),
        PointVariant::FloatBox { .. } => format!("Successfully indexed a floating point bounding box."),
    }
}

fn main() {
    let int_coord = PointVariant::IntPoint { x: 10, y: 20 };
    let float_coord = PointVariant::FloatBox { min_x: -5.0, max_x: 5.0, min_y: 1.0, max_y: 10.0 };

    println!("Input 1: {}", int_coord);
    let result1 = process_coordinate(int_coord);
    println!("Result 1: {}
", result1);

    println!("Input 2: {}", float_coord);
    let result2 = process_coordinate(float_coord);
    println!("Result 2: {}", result2);
}

use std::fmt::{self, Display};

#[derive(Debug, PartialEq, Eq, Clone, Copy)]
enum ModelState {
    Uninitialized,
    Loading,
    Ready,
    InferenceRunning,
    Failed,
}

impl Display for ModelState {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            ModelState::Uninitialized => write!(f, "Uninitialized"),
            ModelState::Loading => write!(f, "Loading Weights"),
            ModelState::Ready => write!(f, "Model Ready for Inference"),
            ModelState::InferenceRunning => write!(f, "Inferencing... Keep it clean!"),
            ModelState::Failed => write!(f, "Error: Check Logs"),
        }
    }
}

fn main() {
    let mut state = ModelState::Uninitialized;
    println!("Initial State: {}", state);

    state = ModelState::Loading;
    println!("Current State: {}", state);

    if state == ModelState::Loading {
        println!("Successfully loaded initial weights.");
        state = ModelState::Ready;
    }

    println!("Final Check: {}", state);
}

use std::collections::HashMap;

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
struct ColorType {
    r: u8,
    g: u8,
    b: u8,
}

impl ColorType {
    fn new(r: u8, g: u8, b: u8) -> Self {
        ColorType { r, g, b }
    }
}

fn count_adjacent_groups(colors: &[ColorType]) -> HashMap<ColorType, usize> {
    if colors.is_empty() {
        return HashMap::new();
    }

    let mut color_counts: HashMap<ColorType, usize> = HashMap::new();
    let mut current_color: Option<ColorType> = None;
    let mut group_count: HashMap<ColorType, usize> = HashMap::new();

    for &color in colors.iter() {
        if let Some(prev_color) = current_color {
            if color == prev_color {
                group_count.entry(color).and_modify(|count| *count += 1);
            } else {
                let mut new_group = HashMap::new();
                new_group.insert(color, 1);
                for (k, v) in group_count.iter() {
                    new_group.entry(*k).or_insert(0); 
                }
                group_count = new_group;
            }
        }
        current_color = Some(color);
    }

    group_count
}

fn main() {
    let colors1 = vec![ColorType::new(255, 0, 0), ColorType::new(0, 255, 0), ColorType::new(255, 0, 0)];
    println!("Test Case 1: {:?}", count_adjacent_groups(&colors1));

    let colors2 = vec![ColorType::new(0, 0, 255), ColorType::new(0, 0, 255), ColorType::new(0, 0, 255)];
    println!("Test Case 2: {:?}", count_adjacent_groups(&colors2));

    let colors3 = vec![ColorType::new(1, 1, 1), ColorType::new(2, 2, 2), ColorType::new(1, 1, 1)];
    println!("Test Case 3: {:?}", count_adjacent_groups(&colors3));
}

use std::collections::HashMap;

#[derive(Debug)]
enum CalculatorResult {
    Integer(i64),
    Decimal(f64),
    UnknownOperation,
}

struct OperationProcessor {
    history: HashMap<String, f64>,
}

impl OperationProcessor {
    fn new() -> Self {
        OperationProcessor {
            history: HashMap::new() 
        }
    }

    fn record_value(&mut self, key: &str, value: f64) {
        self.history.insert(String::from(key), value);
    }

    fn get_result(&self, operation: &str, operand1: f64, operand2: f64) -> CalculatorResult {
        if operation == "add" {
            return CalculatorResult::Decimal(operand1 + operand2);
        } else if operation == "multiply" {
            return CalculatorResult::Decimal(operand1 * operand2);
        } else if operation == "constant_check" {
            let stored: f64 = self.history.get("initial_seed").copied().unwrap_or(0.0);
            if (stored - 100.0).abs() < 1e-9 {
                return CalculatorResult::Integer(1); 
            } else {
                return CalculatorResult::Decimal(stored);
            }
        } else {
            CalculatorResult::UnknownOperation
        }
    }
}

fn main() {
    let mut processor = OperationProcessor::new();
    processor.record_value("initial_seed", 100.0);

    let result1 = processor.get_result("add", 5.5, 3.2);
    println!("Result of adding: {:?}", result1);

    let result2 = processor.get_result("constant_check", 0.0, 0.0);
    println!("Result check: {:?}", result2);

    let result3 = processor.get_result("unknown", 1.0, 1.0);
    println!("Result unknown op: {:?}", result3);
}

use std::collections::HashMap;

#[derive(Debug, PartialEq, Eq)]
enum LintError {
    MissingFile(String),
    InvalidFormat(String),
    UnknownToken(String),
}

impl From<std::io::Error> for LintError {
    fn from(err: std::io::Error) -> Self {
        LintError::MissingFile(format!("IO Error: {}", err))}
    }

struct LinterContext {
    tokens: HashMap<String, String>,
}

impl LinterContext {
    fn new() -> Self {
        LinterContext { tokens: HashMap::new() }
    }

    fn check_syntax(&self, token_name: &str) -> Result<(), LintError> {
        if !self.tokens.contains_key(token_name) {
            return Err(LintError::UnknownToken(token_name.to_string()));
        }
        Ok(())
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let mut context = LinterContext::new();
    context.tokens.insert("key".to_string(), "value".to_string());

    match context.check_syntax("key") {
        Ok(_) => println!("Syntax check passed."),
        Err(e) => eprintln!("Failed to lint: {:?}", e),
    }

    match context.check_syntax("nonexistent") {
        Ok(_) => (),
        Err(e) => println!("Successfully caught error case: {:?}", e),
    }

    Ok(())
}
